function broadCategory(name) {
  for (const category of broadCategoryOrder) {
    if (broadCategories[category]?.has(name)) return category;
  }
  return 'Other / Supplies';
}


function vialSafeName(value) {
  return String(value)
    .replaceAll('+', ' plus ')
    .replaceAll('/', ' ')
    .replaceAll('静', 'iv')
    .replace(/[^A-Za-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .toLowerCase()
    .replace(/-+/g, '-')
    .slice(0, 120);
}
function vialImagePath(name, code, amount) {
  return `/jedi-research-vials/${vialSafeName(name)}__${vialSafeName(code)}__${vialSafeName(amount)}.png`;
}

const byName = new Map();
for (const [code,name,amount,vials,price] of rows) {
  if (!byName.has(name)) byName.set(name, []);
  byName.get(name).push({code, amount, vials, price, image: vialImagePath(name, code, amount)});
}

function parseComparableAmount(amount) {
  const normalized = String(amount).toLowerCase().replace('µg', 'mcg').replace(/,/g, '');
  const match = normalized.match(/([0-9]+(?:\.[0-9]+)?)\s*(mcg|mg|iu|ml)\b/);
  if (!match) return null;
  let unit = match[2];
  let value = Number(match[1]);
  if (!Number.isFinite(value) || value <= 0) return null;
  if (unit === 'mcg') value = value / 1000, unit = 'mg';
  return { value, unit };
}

function addSavings(variants) {
  const parsed = variants.map(v => ({ ...v, comparable: parseComparableAmount(v.amount), perVial: Number(v.price) / (Number(String(v.vials).match(/\d+/)?.[0]) || 10) }));
  for (const v of parsed) {
    if (!v.comparable) continue;
    const lower = parsed
      .filter(x => x !== v && x.comparable && x.comparable.unit === v.comparable.unit && x.comparable.value < v.comparable.value)
      .sort((a, b) => b.comparable.value - a.comparable.value)[0];
    if (!lower) continue;
    const equivalentLowerCost = (v.comparable.value / lower.comparable.value) * lower.perVial;
    const savings = equivalentLowerCost - v.perVial;
    if (savings > 0.01) {
      v.savings = Math.round(savings * 100) / 100;
      v.savingsBase = lower.amount;
    }
  }
  return parsed.map(({ comparable, ...v }) => v);
}


